import { formatNumber } from '@/lib/format'

interface Metric {
  metricName: string
  value: number
}

export default function MetricsGrid({ metrics }: { metrics?: Metric[] }) {
  if (!metrics?.length) {
    return (
      <div className="rounded-2xl border border-zinc-800 bg-zinc-900/70 p-6 text-sm text-zinc-400">
        Sin métricas disponibles.
      </div>
    )
  }

  return (
    <div className="grid gap-4 md:grid-cols-2 xl:grid-cols-4">
      {metrics.map((metric) => (
        <div
          key={metric.metricName}
          className="rounded-2xl border border-zinc-800 bg-zinc-900/70 p-5 shadow-lg shadow-black/20"
        >
          <div className="text-xs uppercase tracking-[0.12em] text-zinc-500">
            {metric.metricName.replaceAll('_', ' ')}
          </div>
          <div className="mt-3 text-3xl font-semibold text-white">
            {formatNumber(metric.value)}
          </div>
        </div>
      ))}
    </div>
  )
}
