import { t } from '@/i18n/es'
import { formatDate } from '@/lib/format'

interface PolicyCardProps {
  policy: {
    title?: string
    description?: string
    country?: string
    date?: string
    actors?: string[]
    objectives?: string[]
  }
}

function BadgeList({ items }: { items?: string[] }) {
  if (!items?.length) {
    return <span className="text-zinc-500">-</span>
  }

  return (
    <div className="flex flex-wrap gap-2">
      {items.map((item) => (
        <span
          key={item}
          className="rounded-full border border-zinc-800 bg-zinc-950 px-3 py-1 text-xs text-zinc-300"
        >
          {item}
        </span>
      ))}
    </div>
  )
}

function InfoRow({
  label,
  value,
}: {
  label: string
  value: React.ReactNode
}) {
  return (
    <div className="grid gap-2 border-t border-zinc-900 py-4 md:grid-cols-[160px_1fr]">
      <div className="text-sm font-medium text-zinc-500">{label}</div>
      <div className="text-sm text-zinc-200">{value}</div>
    </div>
  )
}

export default function PolicyCard({ policy }: PolicyCardProps) {
  return (
    <div className="rounded-2xl border border-zinc-800 bg-zinc-900/70 p-6 shadow-2xl shadow-black/20 backdrop-blur">
      <InfoRow label={t.policyTitle} value={policy.title ?? '-'} />
      <InfoRow label={t.policyDescription} value={policy.description ?? '-'} />
      <InfoRow label={t.policyCountry} value={policy.country ?? '-'} />
      <InfoRow label={t.policyDate} value={formatDate(policy.date)} />
      <InfoRow label={t.policyActors} value={<BadgeList items={policy.actors} />} />
      <InfoRow label={t.policyObjectives} value={<BadgeList items={policy.objectives} />} />
    </div>
  )
}
