'use client'

import { useEffect, useState } from 'react'
import { fetchPolicyEvaluation } from '@/lib/api'
import { t } from '@/i18n/es'

import PageHeader from '@/components/layout/PageHeader'
import SectionTitle from '@/components/layout/SectionTitle'
import PolicyCard from '@/components/policy/PolicyCard'
import MetricsGrid from '@/components/metrics/MetricsGrid'
import MetricsChart from '@/components/metrics/MetricsChart'
import IndicatorsGrid from '@/components/indicators/IndicatorsGrid'
import ScenarioComparison from '@/components/scenarios/ScenarioComparison'

export default function Home() {
  const [data, setData] = useState<any>(null)

  useEffect(() => {
    fetchPolicyEvaluation().then(setData)
  }, [])

  if (!data) {
    return (
      <main className="min-h-screen bg-black px-6 py-10 text-white md:px-10">
        <PageHeader />
        <div className="mt-10 rounded-2xl border border-zinc-800 bg-zinc-900/70 p-6 text-zinc-400">
          {t.loading}
        </div>
      </main>
    )
  }

  const contextIndicators = data?.context?.indicators ?? data?.policyContext?.indicators ?? {}

  return (
    <main className="min-h-screen bg-black px-6 py-10 text-white md:px-10">
      <div className="mx-auto max-w-7xl space-y-10">
        <PageHeader />

        <section>
          <SectionTitle title={t.policyOverview} />
          <PolicyCard policy={data.policy} />
        </section>

        <section className="space-y-5">
          <SectionTitle
            title={t.keyMetrics}
            description="Indicadores derivados del motor analítico para evaluar la decisión política."
          />
          <MetricsGrid metrics={data.metrics} />
          <MetricsChart metrics={data.metrics} />
        </section>

        <section>
          <SectionTitle
            title={t.contextIndicators}
            description="Variables del contexto utilizadas para interpretar la política y su posible impacto."
          />
          <IndicatorsGrid indicators={contextIndicators} />
        </section>

        <section>
          <SectionTitle
            title={t.scenarioComparison}
            description="Comparación entre el escenario base y escenarios alternativos plausibles."
          />
          <ScenarioComparison scenarios={data.scenarios} />
        </section>
      </div>
    </main>
  )
}
